testbench:
`timescale 1ns/1ps
module tb;
  logic clk, rst_n, sig;
  logic pulse;

  edge_detect dut(.clk(clk), .rst_n(rst_n), .sig(sig), .pulse(pulse));

  always #5 clk = ~clk;

  task step;
    begin
      @(posedge clk); #1;
    end
  endtask

  initial begin
    clk = 0; rst_n = 0; sig = 0;
    step();
    if (pulse !== 0) $fatal(1, "pulse should be 0 during reset");

    rst_n = 1;
    step();
    if (pulse !== 0) $fatal(1, "pulse should remain 0");

    sig = 1;
    step();
    if (pulse !== 1) $fatal(1, "pulse should be 1 on rising edge");

    step();
    if (pulse !== 0) $fatal(1, "pulse should drop after one cycle");

    sig = 0;
    step();
    if (pulse !== 0) $fatal(1, "pulse should stay 0 on falling edge");

    sig = 1;
    step();
    if (pulse !== 1) $fatal(1, "pulse should rise again");

    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module edge_detect(input logic clk, input logic rst_n, input logic sig, output logic pulse);
  logic sig_d;
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      sig_d <= 1'b0;
      pulse <= 1'b0;
    end else begin
      pulse <= sig & ~sig_d;
      sig_d <= sig;
    end
  end
endmodule
